        cost = 0
        for i in range(len(self.warehouse_inventory)):
            for j in range(len(self.port_demand)):
                if solution[i][j] > 0:
                    cost += self.distance_matrix[i][j] * self.cost_per_km * min(solution[i][j], 2) / 2
        return cost

    def is_feasible(self, solution):
        for i in range(len(self.warehouse_inventory)):
            if sum([solution[i][j] for j in range(len(self.port_demand))]) > self.warehouse_inventory[i]:
                return False
        for j in range(len(self.port_demand)):
