                return False
        return True

    def hyperheuristic(self, max_iterations=1000):
        operators = [
            {"name": "greedy", "apply": lambda solution: self.greedy_operator(solution)},
            {"name": "local_search", "apply": lambda solution: self.local_search_operator(solution)},
            {"name": "perturbation", "apply": lambda solution: self.perturbation_operator(solution)},
        ]

        best_solution = None
        best_cost = float('inf')
        for _ in range(max_iterations):
            current_solution = [[random.randint(0, 2) for j in range(len(self.port_demand))] for i in range(len(self.warehouse_inventory))]
            while not self.is_feasible(current_solution):
                operator_name = random.choice(list({op["name"] for op in operators}))
